mapper.select:
select c.id, c.name, c.room, c.begin_date, c.end_date, c.master_id, c.subject, c.create_time, c.update_time, e.name as masterName, (case when now() > c.end_date then '已结课' when c.begin_date > now() then '未开班' else '在读中' end) as status from clazz c left join emp e on c.master_id = e.id
c.name like concat('%',#{name},'%')
and c.end_date between #{begin} and #{end}
